"use client";

import { useState, useRef, useCallback } from "react";
import { Mic, MicOff, Loader2 } from "lucide-react";
import { analyzeVoice } from "@/lib/api";
import { useChatStore } from "@/store/chatStore";

export function VoiceRecorder() {
  const [isRecording, setIsRecording] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const chunksRef = useRef<Blob[]>([]);

  const { sessionId, setSessionId, addUserMessage, addAssistantMessage, setCurrentMood } =
    useChatStore();

  const startRecording = useCallback(async () => {
    setError(null);
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new MediaRecorder(stream, {
        mimeType: "audio/webm;codecs=opus",
      });
      mediaRecorderRef.current = mediaRecorder;
      chunksRef.current = [];

      mediaRecorder.ondataavailable = (e) => {
        if (e.data.size > 0) chunksRef.current.push(e.data);
      };

      mediaRecorder.onstop = async () => {
        stream.getTracks().forEach((t) => t.stop());
        const audioBlob = new Blob(chunksRef.current, { type: "audio/webm" });

        setIsProcessing(true);
        try {
          const result = await analyzeVoice(audioBlob, sessionId || undefined);

          // Show transcribed text as user message
          addUserMessage(`🎙️ "${result.transcribed_text}"`);

          // Update session
          if (!sessionId) setSessionId(result.chat_response.session_id);

          // Add assistant response
          addAssistantMessage(result.chat_response.response, result.chat_response);
          setCurrentMood(result.detected_emotion, result.mood_level);
        } catch (err: unknown) {
          const message = err instanceof Error ? err.message : "Voice analysis failed";
          setError(message);
        } finally {
          setIsProcessing(false);
        }
      };

      mediaRecorder.start();
      setIsRecording(true);
    } catch {
      setError("Microphone access denied. Please allow microphone access.");
    }
  }, [sessionId, setSessionId, addUserMessage, addAssistantMessage, setCurrentMood]);

  const stopRecording = useCallback(() => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
    }
  }, [isRecording]);

  if (isProcessing) {
    return (
      <button
        disabled
        className="p-3 rounded-full bg-purple-500/20 border border-purple-500/30 text-purple-400"
        title="Processing voice..."
      >
        <Loader2 size={20} className="animate-spin" />
      </button>
    );
  }

  return (
    <div className="flex flex-col items-center gap-1">
      <button
        onClick={isRecording ? stopRecording : startRecording}
        className={`p-3 rounded-full border transition-all duration-200 ${
          isRecording
            ? "bg-red-500/20 border-red-500/50 text-red-400 animate-pulse hover:bg-red-500/30"
            : "bg-white/5 border-white/10 text-slate-400 hover:bg-white/10 hover:text-white hover:border-white/20"
        }`}
        title={isRecording ? "Stop recording" : "Start voice check-in"}
      >
        {isRecording ? <MicOff size={20} /> : <Mic size={20} />}
      </button>
      {error && (
        <p className="text-red-400 text-xs max-w-[200px] text-center">{error}</p>
      )}
    </div>
  );
}
