"use client";

import { useCallback, useRef, useState } from "react";

export type VoiceGender = "female" | "male";

export function useTTS() {
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [voiceGender, setVoiceGender] = useState<VoiceGender>("female");
  const utteranceRef = useRef<SpeechSynthesisUtterance | null>(null);

  const getVoice = useCallback((gender: VoiceGender): SpeechSynthesisVoice | null => {
    const voices = window.speechSynthesis.getVoices();
    if (voices.length === 0) return null;

    // Female voice preferences
    const femaleKeywords = ["female", "woman", "girl", "zira", "samantha", "victoria",
      "karen", "moira", "tessa", "fiona", "veena", "susan", "kate"];
    // Male voice preferences
    const maleKeywords = ["male", "man", "guy", "david", "mark", "daniel", "alex",
      "fred", "jorge", "thomas", "lee", "rishi"];

    const keywords = gender === "female" ? femaleKeywords : maleKeywords;

    // Try to find a matching voice
    const match = voices.find((v) =>
      keywords.some((kw) => v.name.toLowerCase().includes(kw))
    );
    if (match) return match;

    // Fallback: pick by index (even = female, odd = male)
    const englishVoices = voices.filter((v) => v.lang.startsWith("en"));
    if (englishVoices.length === 0) return voices[0];
    return gender === "female" ? englishVoices[0] : englishVoices[1] || englishVoices[0];
  }, []);

  const speak = useCallback(
    (text: string) => {
      if (!("speechSynthesis" in window)) return;

      // Stop any current speech
      window.speechSynthesis.cancel();

      // Clean text — remove markdown bold/italic markers
      const cleanText = text
        .replace(/\*\*(.*?)\*\*/g, "$1")
        .replace(/\*(.*?)\*/g, "$1")
        .replace(/#{1,6}\s/g, "")
        .replace(/🎵|💡|🌬️|📦|🫁|✅|🗂️|☕|🚪|🤝|📉|🔍|🏙️|💬|🌐|📱|💪|✍️|🤲/g, "")
        .trim();

      const utterance = new SpeechSynthesisUtterance(cleanText);
      utteranceRef.current = utterance;

      // Wait for voices to load if needed
      const setVoiceAndSpeak = () => {
        const voice = getVoice(voiceGender);
        if (voice) utterance.voice = voice;
        utterance.rate = 0.92;
        utterance.pitch = voiceGender === "female" ? 1.1 : 0.85;
        utterance.volume = 1;

        utterance.onstart = () => setIsSpeaking(true);
        utterance.onend = () => setIsSpeaking(false);
        utterance.onerror = () => setIsSpeaking(false);

        window.speechSynthesis.speak(utterance);
      };

      const voices = window.speechSynthesis.getVoices();
      if (voices.length === 0) {
        window.speechSynthesis.onvoiceschanged = setVoiceAndSpeak;
      } else {
        setVoiceAndSpeak();
      }
    },
    [voiceGender, getVoice]
  );

  const stop = useCallback(() => {
    window.speechSynthesis.cancel();
    setIsSpeaking(false);
  }, []);

  return { speak, stop, isSpeaking, voiceGender, setVoiceGender };
}
