"use client";

import { Volume2, VolumeX, User, Users } from "lucide-react";
import { VoiceGender } from "@/hooks/useTTS";

interface TTSControlsProps {
  text: string;
  isSpeaking: boolean;
  voiceGender: VoiceGender;
  onSpeak: (text: string) => void;
  onStop: () => void;
  onGenderChange: (gender: VoiceGender) => void;
}

export function TTSControls({
  text,
  isSpeaking,
  voiceGender,
  onSpeak,
  onStop,
  onGenderChange,
}: TTSControlsProps) {
  return (
    <div className="flex items-center gap-2 mt-2">
      {/* Speak / Stop button */}
      <button
        onClick={() => (isSpeaking ? onStop() : onSpeak(text))}
        className={`flex items-center gap-1.5 px-3 py-1.5 rounded-full text-xs font-medium border transition-all duration-200 ${
          isSpeaking
            ? "bg-teal-500/20 border-teal-500/40 text-teal-300 hover:bg-teal-500/30"
            : "bg-white/5 border-white/10 text-slate-400 hover:bg-white/10 hover:text-white"
        }`}
        title={isSpeaking ? "Stop speaking" : "Read aloud"}
      >
        {isSpeaking ? (
          <>
            <VolumeX size={12} className="animate-pulse" />
            Stop
          </>
        ) : (
          <>
            <Volume2 size={12} />
            Listen
          </>
        )}
      </button>

      {/* Voice gender toggle */}
      <div className="flex items-center bg-white/5 border border-white/10 rounded-full overflow-hidden">
        <button
          onClick={() => onGenderChange("female")}
          className={`flex items-center gap-1 px-2.5 py-1.5 text-xs transition-all duration-200 ${
            voiceGender === "female"
              ? "bg-pink-500/30 text-pink-300"
              : "text-slate-500 hover:text-slate-300"
          }`}
          title="Female voice"
        >
          <User size={10} />
          ♀
        </button>
        <button
          onClick={() => onGenderChange("male")}
          className={`flex items-center gap-1 px-2.5 py-1.5 text-xs transition-all duration-200 ${
            voiceGender === "male"
              ? "bg-blue-500/30 text-blue-300"
              : "text-slate-500 hover:text-slate-300"
          }`}
          title="Male voice"
        >
          <Users size={10} />
          ♂
        </button>
      </div>
    </div>
  );
}
